import { useState } from 'react';
import { X, Search } from 'lucide-react';
import { useToast } from '../hooks/useToast.jsx';
import { createActivity } from '../lib/api.js';

export default function ActivityDrawer({ isOpen, onClose, stopId, onActivityAdded }) {
  const { addToast } = useToast();
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    type: 'misc',
    time_slot: '10:00',
    cost: ''
  });
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const act = await createActivity({
        ...formData,
        stop_id: stopId,
        cost: formData.cost ? Number(formData.cost) : 0
      });
      onActivityAdded(act);
      addToast('Operation scheduled successfully', 'success');
      onClose();
    } catch {
      addToast('Failed to schedule operation', 'error');
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <>
      <div className="fixed inset-0 bg-slate-900/30 backdrop-blur-sm z-40 transition-opacity" onClick={onClose} />
      <div className="fixed inset-y-0 right-0 w-full sm:w-[400px] bg-white shadow-2xl z-50 flex flex-col border-l border-slate-200 animate-in slide-in-from-right duration-300">
        <div className="flex items-center justify-between px-6 py-4 border-b border-slate-200 bg-slate-50">
          <h2 className="text-sm font-semibold text-slate-900 uppercase tracking-wider">Schedule Operation</h2>
          <button onClick={onClose} className="p-1 rounded-md text-slate-400 hover:text-slate-600 hover:bg-slate-200 transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-6 space-y-5 custom-scrollbar">

          <div>
            <label className="erp-label">Operation Identifier *</label>
            <input
              type="text"
              required
              autoFocus
              value={formData.name}
              onChange={e => setFormData({ ...formData, name: e.target.value })}
              className="erp-input"
              placeholder="e.g. Stakeholder Meeting / Transit"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="erp-label">Category</label>
              <select
                value={formData.type}
                onChange={e => setFormData({ ...formData, type: e.target.value })}
                className="erp-input"
              >
                <option value="lodging">Lodging</option>
                <option value="flight">Flight</option>
                <option value="transit">Transit</option>
                <option value="dining">Dining</option>
                <option value="activity">Activity</option>
                <option value="misc">Miscellaneous</option>
              </select>
            </div>
            <div>
              <label className="erp-label">Time Window</label>
              <input
                type="time"
                value={formData.time_slot}
                onChange={e => setFormData({ ...formData, time_slot: e.target.value })}
                className="erp-input"
              />
            </div>
          </div>

          <div>
            <label className="erp-label">Allocated Cost (USD)</label>
            <input
              type="number"
              value={formData.cost}
              onChange={e => setFormData({ ...formData, cost: e.target.value })}
              className="erp-input"
              placeholder="0.00"
            />
          </div>

          <div>
            <label className="erp-label">Operational Briefing (Optional)</label>
            <textarea
              rows={4}
              value={formData.description}
              onChange={e => setFormData({ ...formData, description: e.target.value })}
              className="erp-input resize-none"
              placeholder="Addresses, contact info, specific instructions..."
            />
          </div>

        </form>

        <div className="p-6 border-t border-slate-200 bg-slate-50 flex gap-3 justify-end">
          <button type="button" onClick={onClose} className="erp-button-secondary w-full sm:w-auto">
            Cancel
          </button>
          <button type="submit" disabled={loading} className="erp-button w-full sm:w-auto">
            {loading ? 'Committing...' : 'Schedule Operation'}
          </button>
        </div>
      </div>
    </>
  );
}

import { useState } from 'react';
import Modal from './Modal.jsx';
import { createStop } from '../lib/api.js';
import { useToast } from '../hooks/useToast.jsx';

export default function CitySearchModal({ isOpen, onClose, tripId, onStopAdded }) {
  const { addToast } = useToast();
  const [formData, setFormData] = useState({
    city_name: '',
    arrival_date: '',
    departure_date: ''
  });
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.city_name || !formData.arrival_date) {
      return addToast('City name and arrival date are required parameters', 'error');
    }

    setLoading(true);
    try {
      const newStop = await createStop({ ...formData, trip_id: tripId });
      onStopAdded(newStop);
      addToast('Travel node initialized', 'success');
      onClose();
    } catch (err) {
      addToast('Failed to initialize node', 'error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Modal open={isOpen} onClose={onClose} title="Initialize Travel Node">
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="erp-label">Node Identifier (City/Location)</label>
          <input
            type="text"
            required
            autoFocus
            value={formData.city_name}
            onChange={e => setFormData({ ...formData, city_name: e.target.value })}
            placeholder="e.g. Tokyo, JP"
            className="erp-input"
          />
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="erp-label">Arrival Date</label>
            <input
              type="date"
              required
              value={formData.arrival_date}
              onChange={e => setFormData({ ...formData, arrival_date: e.target.value })}
              className="erp-input"
            />
          </div>
          <div>
            <label className="erp-label">Departure Date</label>
            <input
              type="date"
              value={formData.departure_date}
              onChange={e => setFormData({ ...formData, departure_date: e.target.value })}
              className="erp-input"
            />
          </div>
        </div>

        <div className="pt-2 flex justify-end gap-3">
          <button type="button" onClick={onClose} className="erp-button-secondary py-1.5 px-4 text-xs">
            Cancel
          </button>
          <button type="submit" disabled={loading} className="erp-button py-1.5 px-4 text-xs">
            {loading ? 'Processing...' : 'Initialize Node'}
          </button>
        </div>
      </form>
    </Modal>
  );
}

import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth.jsx';
import { Map, User, Shield, Compass, ChevronLeft, ChevronRight, LogOut, Search, Activity, Settings, Calendar, DollarSign, ListTodo, FileText } from 'lucide-react';
import { useState } from 'react';

const NAV_ITEMS = [
  { label: 'Dashboard', path: '/dashboard', icon: Compass },
  { label: 'My Trips', path: '/trips', icon: Map },
  { label: 'Profile', path: '/profile', icon: User },
];

export default function SidebarLayout({ children, title, subtitle, hideSidebar = false }) {
  const { user, profile, signOut } = useAuth();
  const location = useLocation();
  const [collapsed, setCollapsed] = useState(false);

  const activePath = location.pathname;

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans text-slate-900">

      {/* SIDEBAR */}
      {!hideSidebar && (
        <aside className={`flex flex-col bg-slate-900 text-slate-300 transition-all duration-300 border-r border-slate-800 ${collapsed ? 'w-16' : 'w-64'} h-full shrink-0 relative`}>

          <div className="h-14 flex items-center px-4 shrink-0 border-b border-slate-800 bg-slate-950/50">
            <div className="w-8 h-8 bg-indigo-600 rounded-md flex items-center justify-center shrink-0">
              <Map className="w-4 h-4 text-white" />
            </div>
            {!collapsed && <span className="ml-3 font-semibold text-white tracking-wide truncate">Traveloop ERP</span>}
          </div>

          <div className="flex-1 overflow-y-auto py-4 custom-scrollbar">
            <div className="px-3 mb-2">
              {!collapsed && <div className="text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-2 px-1">Navigation</div>}
              <div className="space-y-1">
                {NAV_ITEMS.map(item => {
                  const active = activePath.startsWith(item.path);
                  return (
                    <Link
                      key={item.path}
                      to={item.path}
                      className={`flex items-center px-2 py-2 rounded-md transition-colors ${active ? 'bg-indigo-600/20 text-indigo-400' : 'hover:bg-slate-800 hover:text-white'}`}
                      title={collapsed ? item.label : ''}
                    >
                      <item.icon className="w-5 h-5 shrink-0" />
                      {!collapsed && <span className="ml-3 text-sm font-medium truncate">{item.label}</span>}
                      {active && !collapsed && <div className="ml-auto w-1 h-4 bg-indigo-500 rounded-full" />}
                    </Link>
                  );
                })}

                {profile?.role === 'admin' && (
                  <Link
                    to="/admin"
                    className={`flex items-center px-2 py-2 rounded-md transition-colors ${activePath.startsWith('/admin') ? 'bg-indigo-600/20 text-indigo-400' : 'hover:bg-slate-800 hover:text-white'}`}
                    title={collapsed ? 'Admin' : ''}
                  >
                    <Shield className="w-5 h-5 shrink-0" />
                    {!collapsed && <span className="ml-3 text-sm font-medium truncate">Admin Console</span>}
                  </Link>
                )}
              </div>
            </div>
          </div>

          <div className="p-3 border-t border-slate-800">
             <button 
                onClick={signOut}
                className="w-full flex items-center px-2 py-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-md transition-colors"
                title={collapsed ? 'Sign Out' : ''}
              >
                <LogOut className="w-5 h-5 shrink-0" />
                {!collapsed && <span className="ml-3 text-sm font-medium">Sign Out</span>}
             </button>
          </div>

          <button 
            onClick={() => setCollapsed(!collapsed)}
            className="absolute -right-3 top-20 w-6 h-6 bg-slate-800 border border-slate-700 rounded-full flex items-center justify-center text-slate-400 hover:text-white transition-colors z-10"
          >
            {collapsed ? <ChevronRight className="w-3 h-3" /> : <ChevronLeft className="w-3 h-3" />}
          </button>
        </aside>
      )}

      {/* MAIN CONTENT AREA */}
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">

        {/* TOPBAR */}
        <header className="h-14 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 z-10 shadow-sm">
          <div className="flex items-center gap-4 flex-1 min-w-0">
            <div>
               {title && <h1 className="text-lg font-semibold text-slate-900 leading-tight truncate">{title}</h1>}
               {subtitle && <p className="text-xs text-slate-500 leading-tight truncate">{subtitle}</p>}
            </div>
          </div>
          <div className="flex items-center gap-4 shrink-0">
             <div className="hidden sm:flex relative">
               <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
               <input type="text" placeholder="Search..." className="w-48 pl-9 pr-3 py-1.5 text-sm bg-slate-50 border border-slate-200 rounded-md focus:outline-none focus:ring-1 focus:ring-indigo-500 focus:bg-white transition-colors" />
             </div>
             <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center border border-indigo-200 shrink-0">
                <span className="text-indigo-700 font-semibold text-sm">{(profile?.name || user?.email || 'T').charAt(0).toUpperCase()}</span>
             </div>
          </div>
        </header>

        {/* PAGE CONTENT */}
        <main className="flex-1 overflow-y-auto bg-slate-50 relative p-6">
          <div className="max-w-7xl mx-auto">
            {children}
          </div>
        </main>
      </div>

    </div>
  );
}

