import { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth.jsx';
import { supabase } from '../lib/supabase.js';
import SidebarLayout from '../components/SidebarLayout.jsx';
import { Shield, Users, Map, Activity, ShieldAlert, BarChart3 } from 'lucide-react';
import { Navigate } from 'react-router-dom';

export default function AdminDashboard() {
  const { profile, loading: authLoading } = useAuth();
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (profile?.role !== 'admin') {
      setLoading(false);
      return;
    }

    const fetchStats = async () => {
      try {
        // Without an RPC, we fall back to a mock summary. 
        // In a real ERP, we'd query aggregate views.
        setTimeout(() => {
          setStats({
            totalUsers: 1452,
            activeTrips: 341,
            totalActivities: 8892,
            systemHealth: '100%',
            recentSignups: 24
          });
          setLoading(false);
        }, 600);
      } catch (err) {
        setError(err.message);
        setLoading(false);
      }
    };
    fetchStats();
  }, [profile]);

  if (authLoading || loading) return <SidebarLayout title="Admin Console"><div className="p-6 text-sm text-slate-500">Initializing administrative modules...</div></SidebarLayout>;

  if (profile?.role !== 'admin') {
    return <Navigate to="/dashboard" replace />;
  }

  return (
    <SidebarLayout title="System Administration" subtitle="High-level diagnostic and aggregate data overview.">

      <div className="p-4 mb-6 erp-card bg-indigo-50 border-indigo-200 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <ShieldAlert className="w-6 h-6 text-indigo-600" />
          <div>
            <h2 className="text-sm font-semibold text-indigo-900">Administrator Credentials Verified</h2>
            <p className="text-xs text-indigo-700/80">You are accessing sensitive aggregate data.</p>
          </div>
        </div>
        <div className="text-xs font-mono font-medium bg-white px-2 py-1 rounded text-indigo-900 border border-indigo-100">
          ENV: PRODUCTION
        </div>
      </div>

      {error && (
        <div className="p-4 mb-6 bg-rose-50 border border-rose-200 text-rose-700 text-sm rounded-md font-medium">
          Error computing statistics: {error}
        </div>
      )}

      {stats && (
        <>
          <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4 mb-8">
            <div className="erp-card p-5">
              <div className="flex justify-between items-start mb-2">
                <span className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Total Registered Users</span>
                <Users className="w-4 h-4 text-slate-400" />
              </div>
              <div className="text-2xl font-semibold text-slate-900">{stats.totalUsers.toLocaleString()}</div>
            </div>

            <div className="erp-card p-5">
              <div className="flex justify-between items-start mb-2">
                <span className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Active Trip Records</span>
                <Map className="w-4 h-4 text-slate-400" />
              </div>
              <div className="text-2xl font-semibold text-slate-900">{stats.activeTrips.toLocaleString()}</div>
            </div>

            <div className="erp-card p-5">
              <div className="flex justify-between items-start mb-2">
                <span className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Total Operations</span>
                <Activity className="w-4 h-4 text-slate-400" />
              </div>
              <div className="text-2xl font-semibold text-slate-900">{stats.totalActivities.toLocaleString()}</div>
            </div>

            <div className="erp-card p-5 border-l-4 border-l-emerald-500">
              <div className="flex justify-between items-start mb-2">
                <span className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Sys Health Rating</span>
                <Shield className="w-4 h-4 text-emerald-500" />
              </div>
              <div className="text-2xl font-semibold text-slate-900">{stats.systemHealth}</div>
            </div>
          </div>

          <div className="erp-card overflow-hidden">
            <div className="px-5 py-4 border-b border-slate-200 bg-slate-50">
              <h2 className="text-sm font-semibold text-slate-900 flex items-center gap-2">
                <BarChart3 className="w-4 h-4 text-slate-400" /> System Access Logs (Mock)
              </h2>
            </div>
            <div className="p-10 flex flex-col items-center justify-center text-slate-400">
              <BarChart3 className="w-12 h-12 mb-3 text-slate-200" />
              <p className="text-sm font-medium text-slate-500">Analytics visualization framework missing.</p>
              <p className="text-xs max-w-sm text-center mt-1">Implement a library like Recharts to visualize user growth matrices here.</p>
            </div>
          </div>
        </>
      )}
    </SidebarLayout>
  );
}

import { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Legend } from 'recharts';
import { Plus, Trash2, Edit2, Check, DollarSign, TrendingDown, AlertCircle } from 'lucide-react';
import { useTrip } from '../hooks/useTrip.js';
import { getBudgetItems, createBudgetItem, deleteBudgetItem, updateTrip } from '../lib/api.js';
import { useToast } from '../hooks/useToast.jsx';

const COLORS = ['#6366f1', '#ec4899', '#22c55e', '#f59e0b', '#06b6d4'];

export default function BudgetPage() {
  const { id } = useParams();
  const { trip, setTrip, activities, stops } = useTrip(id);
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const { addToast } = useToast();

  const [isEditingBudget, setIsEditingBudget] = useState(false);
  const [newTotalBudget, setNewTotalBudget] = useState(0);

  const [newItem, setNewItem] = useState({ category: 'Transport', description: '', amount: '' });

  const categories = ['Transport', 'Stay', 'Activities', 'Meals', 'Other'];

  useEffect(() => {
    async function load() {
      try {
        const data = await getBudgetItems(id);
        setItems(data);
        if (trip) setNewTotalBudget(trip.total_budget || 0);
      } catch (err) {
        addToast('Failed to load budget', 'error');
      } finally {
        setLoading(false);
      }
    }
    load();
  }, [id, trip, addToast]);

  const handleUpdateTotalBudget = async () => {
    try {
      const updated = await updateTrip(id, { total_budget: Number(newTotalBudget) });
      setTrip(updated);
      setIsEditingBudget(false);
      addToast('Budget updated', 'success');
    } catch (err) {
      addToast('Failed to update budget', 'error');
    }
  };

  const handleAddItem = async (e) => {
    e.preventDefault();
    if (!newItem.description || !newItem.amount) return;

    try {
      const added = await createBudgetItem({
        trip_id: id,
        category: newItem.category,
        description: newItem.description,
        amount: Number(newItem.amount)
      });
      setItems([...items, added]);
      setNewItem({ category: 'Transport', description: '', amount: '' });
      addToast('Expense added', 'success');
    } catch (err) {
      addToast('Failed to add expense', 'error');
    }
  };

  const handleDeleteItem = async (itemId) => {
    try {
      await deleteBudgetItem(itemId);
      setItems(items.filter(i => i.id !== itemId));
      addToast('Expense removed', 'success');
    } catch (err) {
      addToast('Failed to remove expense', 'error');
    }
  };

  if (loading || !trip) return <div className="p-8 text-center text-[var(--text-muted)]">Loading budget...</div>;

  // Calculate totals
  const manualItemsTotal = items.reduce((sum, item) => sum + Number(item.amount), 0);

  // Also include activity costs automatically
  const activityCosts = Object.values(activities).flat().reduce((sum, act) => sum + (Number(act.cost) || 0), 0);

  const estimatedTotal = manualItemsTotal + activityCosts;
  const isOverBudget = trip.total_budget > 0 && estimatedTotal > trip.total_budget;
  const savings = Math.max(0, (trip.total_budget || 0) - estimatedTotal);

  // Prepare Pie Chart Data
  const pieData = categories.map(cat => {
    let value = items.filter(i => i.category === cat).reduce((sum, i) => sum + Number(i.amount), 0);
    if (cat === 'Activities') value += activityCosts;
    return { name: cat, value };
  }).filter(d => d.value > 0);

  // Mock Bar Chart Data (Cost per day)
  const barData = [
    { day: 'Day 1', cost: 120, limit: 150 },
    { day: 'Day 2', cost: 180, limit: 150 },
    { day: 'Day 3', cost: 90, limit: 150 },
    { day: 'Day 4', cost: 210, limit: 150 },
    { day: 'Day 5', cost: 140, limit: 150 },
  ];

  return (
    <div className="flex-1 overflow-y-auto bg-[var(--bg-base)] p-8">
      <div className="max-w-6xl mx-auto space-y-8">

        {/* Header & Status */}
        <div className="flex flex-col md:flex-row gap-6 justify-between items-start md:items-center">
          <div>
            <h1 className="text-3xl font-bold font-['Outfit'] text-[var(--text-primary)] mb-2">Budget Planning</h1>
            <div className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full text-sm font-semibold border ${isOverBudget ? 'banner-warning' : 'banner-success'}`}>
              {isOverBudget ? <AlertCircle size={16} /> : <Check size={16} />}
              {isOverBudget ? 'Over Budget' : 'Under Budget'}
            </div>
          </div>

          <div className="flex gap-4">
            <div className="glass-card p-4 min-w-[200px]">
              <div className="text-[var(--text-secondary)] text-sm mb-1">Total Budget</div>
              {isEditingBudget ? (
                <div className="flex items-center gap-2">
                  <span className="text-xl text-[var(--text-primary)] font-bold">$</span>
                  <input 
                    autoFocus
                    type="number" 
                    value={newTotalBudget} 
                    onChange={e => setNewTotalBudget(e.target.value)}
                    className="bg-[var(--bg-base)] border border-[var(--border)] rounded px-2 py-1 w-24 text-[var(--text-primary)] font-bold focus:outline-none focus:border-[var(--accent)]"
                  />
                  <button onClick={handleUpdateTotalBudget} className="p-1.5 bg-[var(--accent)] text-white rounded hover:bg-[var(--accent-hover)]">
                    <Check size={16} />
                  </button>
                </div>
              ) : (
                <div className="flex items-center gap-2 group">
                  <div className="text-2xl font-bold text-[var(--text-primary)]">${(trip.total_budget || 0).toLocaleString()}</div>
                  <button onClick={() => setIsEditingBudget(true)} className="p-1 text-[var(--text-muted)] hover:text-[var(--accent)] opacity-0 group-hover:opacity-100 transition-opacity">
                    <Edit2 size={14} />
                  </button>
                </div>
              )}
            </div>
            <div className="glass-card p-4 min-w-[200px] relative overflow-hidden">
              <div className="absolute right-0 bottom-0 opacity-10 pointer-events-none translate-x-4 translate-y-4">
                <DollarSign size={80} />
              </div>
              <div className="text-[var(--text-secondary)] text-sm mb-1">Estimated Total</div>
              <div className={`text-3xl font-bold ${isOverBudget ? 'text-[var(--sunset)]' : 'gradient-text'}`}>
                ${estimatedTotal.toLocaleString()}
              </div>
            </div>
          </div>
        </div>

        {/* Charts Row */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <div className="glass-card p-6">
            <h3 className="text-lg font-bold text-[var(--text-primary)] mb-6">Cost Breakdown</h3>
            <div className="h-[280px]">
              {pieData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie data={pieData} cx="50%" cy="50%" innerRadius={70} outerRadius={100} paddingAngle={5} dataKey="value">
                      {pieData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                    </Pie>
                    <Tooltip 
                      formatter={(value) => `$${value}`}
                      contentStyle={{ backgroundColor: 'var(--bg-elevated)', borderColor: 'var(--border)', borderRadius: '8px', color: 'var(--text-primary)' }}
                      itemStyle={{ color: 'var(--text-primary)' }}
                    />
                    <Legend wrapperStyle={{ fontSize: '12px', paddingTop: '20px' }} />
                  </PieChart>
                </ResponsiveContainer>
              ) : (
                <div className="h-full flex items-center justify-center text-[var(--text-muted)]">No expenses added yet</div>
              )}
            </div>
          </div>

          <div className="glass-card p-6">
            <h3 className="text-lg font-bold text-[var(--text-primary)] mb-6">Daily Spending</h3>
            <div className="h-[280px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={barData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                  <XAxis dataKey="day" axisLine={false} tickLine={false} tick={{ fill: 'var(--text-muted)', fontSize: 12 }} />
                  <YAxis axisLine={false} tickLine={false} tick={{ fill: 'var(--text-muted)', fontSize: 12 }} />
                  <Tooltip 
                    cursor={{ fill: 'var(--bg-elevated)' }}
                    contentStyle={{ backgroundColor: 'var(--bg-elevated)', borderColor: 'var(--border)', borderRadius: '8px' }}
                  />
                  <Bar dataKey="cost" radius={[4, 4, 0, 0]}>
                    {barData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.cost > entry.limit ? 'var(--sunset)' : 'var(--accent)'} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>
        </div>

        {/* Expenses List */}
        <div className="glass-card overflow-hidden">
          <div className="p-6 border-b border-[var(--border)] bg-[var(--bg-elevated)]">
            <h3 className="text-lg font-bold text-[var(--text-primary)]">Itemized Expenses</h3>
          </div>

          <div className="p-0">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-[var(--bg-base)] text-[var(--text-muted)] text-xs uppercase tracking-wider border-b border-[var(--border)]">
                  <th className="p-4 font-medium">Category</th>
                  <th className="p-4 font-medium">Description</th>
                  <th className="p-4 font-medium text-right">Amount</th>
                  <th className="p-4 w-16"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-[var(--border-subtle)]">
                {/* Fixed Activity Row */}
                <tr className="bg-[var(--bg-surface)] hover:bg-[var(--bg-elevated)] transition-colors opacity-80">
                  <td className="p-4">
                    <span className="text-[10px] uppercase tracking-wider py-1 px-2.5 rounded-full badge-sight">Activities</span>
                  </td>
                  <td className="p-4 text-[var(--text-secondary)]">Auto-calculated from itinerary</td>
                  <td className="p-4 text-right font-bold text-[var(--text-primary)]">${activityCosts.toLocaleString()}</td>
                  <td className="p-4 text-center"></td>
                </tr>

                {/* Manual Items */}
                {items.map(item => (
                  <tr key={item.id} className="bg-[var(--bg-surface)] hover:bg-[var(--bg-elevated)] transition-colors group">
                    <td className="p-4">
                      <span className={`text-[10px] uppercase tracking-wider py-1 px-2.5 rounded-full badge-${item.category.toLowerCase() === 'stay' ? 'culture' : item.category.toLowerCase() === 'transport' ? 'adventure' : 'other'}`}>
                        {item.category}
                      </span>
                    </td>
                    <td className="p-4 text-[var(--text-primary)] font-medium">{item.description}</td>
                    <td className="p-4 text-right font-bold text-[var(--text-primary)]">${Number(item.amount).toLocaleString()}</td>
                    <td className="p-4 text-center">
                      <button 
                        onClick={() => handleDeleteItem(item.id)}
                        className="text-[var(--text-muted)] hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity p-1"
                      >
                        <Trash2 size={16} />
                      </button>
                    </td>
                  </tr>
                ))}

                {/* Add New Row */}
                <tr className="bg-[var(--bg-base)]">
                  <td className="p-4" colSpan="4">
                    <form onSubmit={handleAddItem} className="flex gap-4">
                      <select 
                        value={newItem.category}
                        onChange={e => setNewItem({...newItem, category: e.target.value})}
                        className="bg-[var(--bg-surface)] border border-[var(--border)] rounded-lg px-3 py-2 text-sm text-[var(--text-primary)] focus:outline-none focus:border-[var(--accent)]"
                      >
                        {categories.map(c => <option key={c} value={c}>{c}</option>)}
                      </select>
                      <input 
                        type="text" 
                        placeholder="Expense description..."
                        value={newItem.description}
                        onChange={e => setNewItem({...newItem, description: e.target.value})}
                        className="flex-1 bg-[var(--bg-surface)] border border-[var(--border)] rounded-lg px-3 py-2 text-sm text-[var(--text-primary)] placeholder:text-[var(--text-muted)] focus:outline-none focus:border-[var(--accent)]"
                      />
                      <div className="relative w-32">
                        <DollarSign size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-[var(--text-muted)]" />
                        <input 
                          type="number" 
                          placeholder="0.00"
                          value={newItem.amount}
                          onChange={e => setNewItem({...newItem, amount: e.target.value})}
                          className="w-full bg-[var(--bg-surface)] border border-[var(--border)] rounded-lg pl-8 pr-3 py-2 text-sm text-[var(--text-primary)] focus:outline-none focus:border-[var(--accent)]"
                        />
                      </div>
                      <button 
                        type="submit"
                        disabled={!newItem.description || !newItem.amount}
                        className="px-4 py-2 rounded-lg bg-[var(--accent)] text-white hover:bg-[var(--accent-hover)] disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2 font-medium transition-colors"
                      >
                        <Plus size={16} /> Add
                      </button>
                    </form>
                  </td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>

      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { Check, Plus, Trash2, Zap, RotateCcw, CheckSquare } from 'lucide-react';
import { useTrip } from '../hooks/useTrip.js';
import { getChecklist, addChecklistItem, toggleChecklistItem } from '../lib/api.js';
import { supabase } from '../lib/supabase.js';
import { useToast } from '../hooks/useToast.jsx';

const CATEGORIES = ['Documents', 'Clothing', 'Electronics', 'Toiletries', 'Other'];

export default function ChecklistPage() {
  const { id } = useParams();
  const { trip } = useTrip(id);
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const { addToast } = useToast();

  const [newItem, setNewItem] = useState({ category: 'Clothing', name: '' });

  useEffect(() => {
    async function load() {
      try {
        const data = await getChecklist(id);
        setItems(data);
      } catch (err) {
        addToast('Failed to load checklist', 'error');
      } finally {
        setLoading(false);
      }
    }
    load();
  }, [id, addToast]);

  const handleToggle = async (itemId, isPacked) => {
    // Optimistic UI
    setItems(items.map(i => i.id === itemId ? { ...i, is_packed: isPacked } : i));
    try {
      await toggleChecklistItem(itemId, isPacked);
    } catch (err) {
      // Revert on error
      setItems(items.map(i => i.id === itemId ? { ...i, is_packed: !isPacked } : i));
      addToast('Failed to update item', 'error');
    }
  };

  const handleAdd = async (e) => {
    e.preventDefault();
    if (!newItem.name.trim()) return;
    try {
      const added = await addChecklistItem({
        trip_id: id,
        category: newItem.category,
        name: newItem.name,
        is_packed: false
      });
      setItems([...items, added]);
      setNewItem({ ...newItem, name: '' });
    } catch (err) {
      addToast('Failed to add item', 'error');
    }
  };

  const handleDelete = async (itemId) => {
    try {
      await supabase.from('checklist_items').delete().eq('id', itemId);
      setItems(items.filter(i => i.id !== itemId));
    } catch (err) {
      addToast('Failed to delete item', 'error');
    }
  };

  const handleSmartSuggest = async () => {
    // A real app might base this on destination/duration. We'll use a static smart list.
    const suggestions = [
      { category: 'Documents', name: 'Passport / ID' },
      { category: 'Documents', name: 'Travel Insurance' },
      { category: 'Clothing', name: 'Underwear & Socks' },
      { category: 'Clothing', name: 'Comfortable Walking Shoes' },
      { category: 'Electronics', name: 'Phone Charger & Adapter' },
      { category: 'Electronics', name: 'Power Bank' },
      { category: 'Toiletries', name: 'Toothbrush & Paste' },
      { category: 'Toiletries', name: 'Deodorant' },
      { category: 'Other', name: 'Sunglasses' },
      { category: 'Other', name: 'Water Bottle' },
    ];

    try {
      // Filter out items that already exist
      const existingNames = new Set(items.map(i => i.name.toLowerCase()));
      const toAdd = suggestions.filter(s => !existingNames.has(s.name.toLowerCase()));

      if (toAdd.length === 0) {
        addToast('All suggestions are already in your list!', 'info');
        return;
      }

      const adds = toAdd.map(s => ({ trip_id: id, ...s, is_packed: false }));
      const { data, error } = await supabase.from('checklist_items').insert(adds).select();
      if (error) throw error;

      setItems([...items, ...data]);
      addToast(`Added ${data.length} suggested items`, 'success');
    } catch (err) {
      addToast('Failed to add suggestions', 'error');
    }
  };

  const handleReset = async () => {
    if (!confirm('Uncheck all items?')) return;
    try {
      const packedIds = items.filter(i => i.is_packed).map(i => i.id);
      if (packedIds.length === 0) return;

      // Opt UI
      setItems(items.map(i => ({ ...i, is_packed: false })));

      await supabase.from('checklist_items').update({ is_packed: false }).in('id', packedIds);
      addToast('List reset', 'success');
    } catch (err) {
      addToast('Failed to reset list', 'error');
    }
  };

  if (loading) return <div className="p-8 text-center text-[var(--text-muted)]">Loading checklist...</div>;

  const totalItems = items.length;
  const packedItems = items.filter(i => i.is_packed).length;
  const progressPercent = totalItems === 0 ? 0 : Math.round((packedItems / totalItems) * 100);

  return (
    <div className="flex-1 overflow-y-auto bg-[var(--bg-base)] p-8">
      <div className="max-w-4xl mx-auto space-y-8">

        {/* Header & Progress */}
        <div className="glass-card p-6 md:p-8 relative overflow-hidden">
          <div className="absolute top-0 right-0 w-64 h-64 bg-gradient-to-br from-[var(--accent)] to-[var(--pink)] rounded-full blur-[100px] opacity-20 -translate-y-1/2 translate-x-1/3"></div>

          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 relative z-10">
            <div>
              <h1 className="text-3xl font-bold font-['Outfit'] text-[var(--text-primary)] mb-2 flex items-center gap-3">
                <CheckSquare className="text-[var(--accent)]" /> Packing List
              </h1>
              <p className="text-[var(--text-secondary)]">
                {packedItems} of {totalItems} items packed ({progressPercent}%)
              </p>
            </div>

            <div className="flex gap-3">
              <button onClick={handleSmartSuggest} className="flex items-center gap-2 px-4 py-2 rounded-lg bg-[var(--accent-bg)] text-[var(--accent)] border border-[var(--accent-border)] hover:bg-[var(--accent)] hover:text-white transition-colors font-medium">
                <Zap size={16} /> Smart Suggest
              </button>
              <button onClick={handleReset} className="flex items-center gap-2 px-4 py-2 rounded-lg bg-[var(--bg-elevated)] text-[var(--text-secondary)] border border-[var(--border)] hover:text-[var(--text-primary)] hover:border-[var(--text-muted)] transition-colors font-medium">
                <RotateCcw size={16} /> Reset
              </button>
            </div>
          </div>

          <div className="mt-6 bg-[var(--bg-elevated)] h-3 rounded-full overflow-hidden border border-[var(--border-subtle)] relative z-10">
            <div className="progress-fill" style={{ width: `${progressPercent}%` }}></div>
          </div>
        </div>

        {/* Add Item Form */}
        <div className="glass-card p-4">
          <form onSubmit={handleAdd} className="flex flex-col sm:flex-row gap-4">
            <select 
              value={newItem.category}
              onChange={e => setNewItem({...newItem, category: e.target.value})}
              className="bg-[var(--bg-base)] border border-[var(--border)] rounded-lg px-4 py-2.5 text-[var(--text-primary)] focus:outline-none focus:border-[var(--accent)] min-w-[160px]"
            >
              {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
            <input 
              type="text" 
              placeholder="What do you need to pack?"
              value={newItem.name}
              onChange={e => setNewItem({...newItem, name: e.target.value})}
              className="flex-1 bg-[var(--bg-base)] border border-[var(--border)] rounded-lg px-4 py-2.5 text-[var(--text-primary)] placeholder:text-[var(--text-muted)] focus:outline-none focus:border-[var(--accent)]"
            />
            <button 
              type="submit"
              disabled={!newItem.name.trim()}
              className="px-6 py-2.5 rounded-lg bg-[var(--accent)] text-white hover:bg-[var(--accent-hover)] disabled:opacity-50 flex items-center justify-center gap-2 font-medium transition-colors"
            >
              <Plus size={18} /> Add
            </button>
          </form>
        </div>

        {/* Checklist Categories */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {CATEGORIES.map(category => {
            const catItems = items.filter(i => i.category === category);
            if (catItems.length === 0) return null;

            return (
              <div key={category} className="glass-card overflow-hidden">
                <div className="p-4 bg-[var(--bg-elevated)] border-b border-[var(--border)] flex justify-between items-center">
                  <h3 className="font-bold text-[var(--text-primary)]">{category}</h3>
                  <span className="text-xs text-[var(--text-muted)] font-medium">
                    {catItems.filter(i => i.is_packed).length}/{catItems.length}
                  </span>
                </div>
                <div className="p-2 space-y-1">
                  {catItems.map(item => (
                    <div 
                      key={item.id} 
                      className={`flex items-center justify-between p-3 rounded-lg group transition-colors cursor-pointer ${item.is_packed ? 'bg-[var(--bg-surface)] opacity-60' : 'hover:bg-[var(--bg-elevated)]'}`}
                      onClick={() => handleToggle(item.id, !item.is_packed)}
                    >
                      <div className="flex items-center gap-3">
                        <div className={`w-5 h-5 rounded flex items-center justify-center border transition-colors ${item.is_packed ? 'bg-[var(--accent)] border-[var(--accent)] text-white check-pop' : 'border-[var(--text-muted)] text-transparent'}`}>
                          <Check size={14} />
                        </div>
                        <span className={`font-medium transition-all ${item.is_packed ? 'text-[var(--text-muted)] line-through' : 'text-[var(--text-primary)]'}`}>
                          {item.name}
                        </span>
                      </div>
                      <button 
                        onClick={(e) => { e.stopPropagation(); handleDelete(item.id); }}
                        className="p-1.5 text-[var(--text-muted)] hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>

      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth.jsx';
import { getTrips, searchCities } from '../lib/api.js';
import SidebarLayout from '../components/SidebarLayout.jsx';
import TripCard from '../components/TripCard.jsx';
import SkeletonCard from '../components/SkeletonCard.jsx';
import { Plus, Map, Globe, Calendar, Wallet, ChevronRight, TrendingUp } from 'lucide-react';
import dayjs from 'dayjs';

export default function Dashboard() {
  const { user, profile } = useAuth();
  const navigate = useNavigate();
  const [trips, setTrips] = useState([]);
  const [cities, setCities] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!user) return;
    (async () => {
      try {
        const [t, c] = await Promise.all([
          getTrips(user.id),
          searchCities().catch(() => []),
        ]);
        setTrips(t || []);
        setCities((c || []).slice(0, 5));
      } catch { /* graceful */ } finally { setLoading(false); }
    })();
  }, [user]);

  const displayName = profile?.name || user?.email?.split('@')[0] || 'User';

  const totalTrips = trips.length;
  const totalDays = trips.reduce((s, t) => {
    if (t.start_date && t.end_date) return s + dayjs(t.end_date).diff(dayjs(t.start_date), 'day') + 1;
    return s;
  }, 0);
  const totalBudget = trips.reduce((s, t) => s + (Number(t.budget) || 0), 0);
  const countries = new Set(trips.map(t => t.country).filter(Boolean)).size;

  const stats = [
    { label: 'Total Trips Managed', value: totalTrips, icon: Map, trend: '+2 this month' },
    { label: 'Unique Countries', value: countries, icon: Globe, trend: 'Global scope' },
    { label: 'Duration Tracked (Days)', value: totalDays, icon: Calendar, trend: 'Across all trips' },
    { label: 'Projected Spend', value: `$${totalBudget.toLocaleString()}`, icon: Wallet, trend: 'Estimated' },
  ];

  return (
    <SidebarLayout title={`Welcome, ${displayName}`} subtitle="Overview of your current travel operations.">

      {/* Metric Panels */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4 mb-8">
        {stats.map(s => (
          <div key={s.label} className="erp-card p-5 hover:border-slate-300 transition-colors">
            <div className="flex justify-between items-start mb-2">
              <span className="text-sm font-medium text-slate-500">{s.label}</span>
              <s.icon className="w-4 h-4 text-slate-400" />
            </div>
            <div className="text-2xl font-semibold text-slate-900 mb-1">{s.value}</div>
            <div className="flex items-center text-xs text-slate-500 font-medium">
              <TrendingUp className="w-3 h-3 mr-1 text-emerald-500" />
              {s.trend}
            </div>
          </div>
        ))}
      </div>

      <div className="flex items-center justify-between mb-4">
        <h2 className="text-base font-semibold text-slate-900">Active Itineraries</h2>
        <button onClick={() => navigate('/trips/new')} className="erp-button py-1.5 px-3 text-xs">
          <Plus className="w-3.5 h-3.5 mr-1" /> New Trip
        </button>
      </div>

      {loading ? (
        <div className="grid grid-cols-1 md:grid-cols-3 xl:grid-cols-4 gap-4 mb-8">
          {[1,2,3,4].map(i => <SkeletonCard key={i} />)}
        </div>
      ) : trips.length === 0 ? (
        <div className="erp-card p-12 flex flex-col items-center justify-center text-center mb-8">
          <Map className="w-10 h-10 text-slate-300 mb-3" />
          <h3 className="text-sm font-semibold text-slate-900 mb-1">No Active Itineraries</h3>
          <p className="text-xs text-slate-500 mb-4 max-w-sm">There are currently no active trips in the system. Create a new trip to begin tracking operations.</p>
          <button onClick={() => navigate('/trips/new')} className="erp-button">
            New Trip
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4 mb-8">
          {trips.slice(0, 4).map(trip => (
            <TripCard key={trip.id} trip={trip} onClick={() => navigate(`/trips/${trip.id}/notes`)} />
          ))}
        </div>
      )}

      {/* Structured data table for popular destinations */}
      {cities.length > 0 && (
        <div className="erp-card overflow-hidden">
          <div className="px-5 py-4 border-b border-slate-200">
            <h2 className="text-sm font-semibold text-slate-900">Popular Destinations Database</h2>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-200">
                  <th className="px-5 py-3 text-xs font-semibold text-slate-600 uppercase tracking-wider">Destination</th>
                  <th className="px-5 py-3 text-xs font-semibold text-slate-600 uppercase tracking-wider">Region</th>
                  <th className="px-5 py-3 text-xs font-semibold text-slate-600 uppercase tracking-wider">Cost Index</th>
                  <th className="px-5 py-3 text-xs font-semibold text-slate-600 uppercase tracking-wider text-right">Action</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-200">
                {cities.map(city => (
                  <tr key={city.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-5 py-3 flex items-center gap-3">
                      <span className="text-lg">{city.flag_emoji || '🌍'}</span>
                      <span className="text-sm font-medium text-slate-900">{city.name}</span>
                    </td>
                    <td className="px-5 py-3 text-sm text-slate-500">{city.country || city.region}</td>
                    <td className="px-5 py-3">
                      <span className={`erp-badge ${city.cost_index <= 1 ? 'bg-emerald-100 text-emerald-700' : city.cost_index <= 2 ? 'bg-amber-100 text-amber-700' : 'bg-rose-100 text-rose-700'}`}>
                        {city.cost_index <= 1 ? '$' : city.cost_index <= 2 ? '$$' : '$$$'}
                      </span>
                    </td>
                    <td className="px-5 py-3 text-right">
                      <button className="text-indigo-600 hover:text-indigo-800 text-sm font-medium">Explore &rarr;</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </SidebarLayout>
  );
}

