import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth.jsx';
import { useToast } from '../hooks/useToast.jsx';
import { getTrips, deleteTrip } from '../lib/api.js';
import SidebarLayout from '../components/SidebarLayout.jsx';
import TripCard from '../components/TripCard.jsx';
import SkeletonCard from '../components/SkeletonCard.jsx';
import EmptyState from '../components/EmptyState.jsx';
import Modal from '../components/Modal.jsx';
import { Map, Plus } from 'lucide-react';

export default function MyTrips() {
  const { user } = useAuth();
  const { addToast } = useToast();
  const navigate = useNavigate();
  const [trips, setTrips] = useState([]);
  const [loading, setLoading] = useState(true);
  const [deleteTarget, setDeleteTarget] = useState(null);

  const fetchTrips = async () => {
    try {
      if (user) {
        const data = await getTrips(user.id);
        setTrips(data || []);
      }
    } catch { /* graceful */ } finally { setLoading(false); }
  };

  useEffect(() => { fetchTrips(); }, [user]);

  const handleDelete = async () => {
    if (!deleteTarget) return;
    try {
      await deleteTrip(deleteTarget.id);
      setTrips(trips.filter(t => t.id !== deleteTarget.id));
      addToast('Trip deleted successfully');
    } catch {
      addToast('Failed to delete trip', 'error');
    } finally {
      setDeleteTarget(null);
    }
  };

  return (
    <SidebarLayout title="My Trips" subtitle="Manage all your active and historic travel records.">

      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-2 text-sm text-slate-500">
          Showing <span className="font-semibold text-slate-900">{trips.length}</span> records
        </div>
        <button onClick={() => navigate('/trips/new')} className="erp-button py-1.5 px-3">
          <Plus className="w-4 h-4 mr-1.5" /> New Trip
        </button>
      </div>

      {loading ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
          {[1,2,3,4,5,6].map(i => <SkeletonCard key={i} />)}
        </div>
      ) : trips.length === 0 ? (
        <EmptyState 
          icon={Map}
          title="No Trips Found"
          message="Your travel records are empty. Create a new trip to begin tracking."
          actionLabel="Create Trip"
          onAction={() => navigate('/trips/new')}
        />
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
          {trips.map(trip => (
            <TripCard 
              key={trip.id} 
              trip={trip} 
              onClick={() => navigate(`/trips/${trip.id}/notes`)}
              onDelete={t => setDeleteTarget(t)}
            />
          ))}
        </div>
      )}

      {/* Delete Confirmation Dialog */}
      <Modal open={!!deleteTarget} onClose={() => setDeleteTarget(null)} title="Delete Trip Record">
        <p className="text-sm text-slate-500 mb-6">
          Are you sure you want to permanently delete the travel record <span className="font-semibold text-slate-900">"{deleteTarget?.name}"</span>? 
          This action cannot be undone.
        </p>
        <div className="flex gap-3 justify-end pt-4 border-t border-slate-200">
          <button onClick={() => setDeleteTarget(null)} className="erp-button-secondary">Cancel</button>
          <button onClick={handleDelete} className="erp-button bg-rose-600 hover:bg-rose-700 focus:ring-rose-500">Confirm Deletion</button>
        </div>
      </Modal>
    </SidebarLayout>
  );
}

import { useState } from 'react';
import { useAuth } from '../hooks/useAuth.jsx';
import { useToast } from '../hooks/useToast.jsx';
import SidebarLayout from '../components/SidebarLayout.jsx';
import { User, Loader2, Save, ShieldAlert, Key } from 'lucide-react';

export default function Profile() {
  const { user, profile, setProfile } = useAuth();
  const { addToast } = useToast();
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    name: profile?.name || '',
    bio: profile?.bio || ''
  });

  const handleUpdate = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await setProfile({ name: formData.name, bio: formData.bio });
      addToast('Profile updated successfully', 'success');
    } catch (err) {
      addToast('Failed to update profile', 'error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <SidebarLayout title="User Preferences" subtitle="Manage your account profile and system preferences.">
      <div className="max-w-4xl mx-auto mt-6 grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Core Settings */}
        <div className="lg:col-span-2 space-y-6">
          <form onSubmit={handleUpdate} className="erp-card overflow-hidden">
            <div className="px-6 py-4 border-b border-slate-200 bg-slate-50 flex items-center gap-3">
              <User className="w-5 h-5 text-slate-400" />
              <h2 className="text-sm font-semibold text-slate-900 uppercase tracking-wider">Identity Information</h2>
            </div>

            <div className="p-6 space-y-5">
              <div>
                <label className="erp-label">Full Name</label>
                <input
                  type="text"
                  value={formData.name}
                  onChange={e => setFormData({ ...formData, name: e.target.value })}
                  className="erp-input max-w-md"
                  placeholder="Operational Handle"
                />
              </div>

              <div>
                <label className="erp-label">Biography / Title</label>
                <textarea
                  rows={4}
                  value={formData.bio}
                  onChange={e => setFormData({ ...formData, bio: e.target.value })}
                  className="erp-input resize-none max-w-full"
                  placeholder="Department, Role, or Context..."
                />
              </div>
            </div>

            <div className="px-6 py-4 bg-slate-50 border-t border-slate-200 flex justify-end">
              <button disabled={loading} className="erp-button">
                {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
                {loading ? 'Saving...' : 'Save Changes'}
              </button>
            </div>
          </form>

          {/* Security (Placeholder) */}
          <div className="erp-card overflow-hidden opacity-75">
            <div className="px-6 py-4 border-b border-slate-200 bg-slate-50 flex items-center gap-3">
              <Key className="w-5 h-5 text-slate-400" />
              <h2 className="text-sm font-semibold text-slate-900 uppercase tracking-wider">Security Diagnostics</h2>
            </div>
            <div className="p-6">
               <p className="text-sm text-slate-500">Security configurations and MFA are currently managed externally via the SSO provider.</p>
            </div>
          </div>
        </div>

        {/* Sidebar Info Panel */}
        <div className="space-y-6">
           <div className="erp-card p-6 border-indigo-200 relative overflow-hidden">
             <div className="absolute top-0 left-0 w-full h-1 bg-indigo-500" />
             <div className="w-16 h-16 rounded shadow-sm bg-indigo-50 border border-indigo-100 flex items-center justify-center mx-auto mb-4">
                <span className="text-2xl font-bold text-indigo-600">{(formData.name || user?.email || 'U').charAt(0).toUpperCase()}</span>
             </div>
             <h3 className="text-center font-bold text-slate-900 text-lg">{formData.name || 'Anonymous User'}</h3>
             <p className="text-center text-sm text-slate-500 mb-6">{user?.email}</p>

             <div className="space-y-3 pt-4 border-t border-slate-100">
               <div className="flex justify-between items-center text-sm">
                 <span className="text-slate-500">System ID</span>
                 <span className="font-mono text-xs text-slate-900 bg-slate-100 px-1 py-0.5 rounded">{user?.id.substring(0, 8)}...</span>
               </div>
               <div className="flex justify-between items-center text-sm">
                 <span className="text-slate-500">Privilege Level</span>
                 <span className={`erp-badge ${profile?.role === 'admin' ? 'bg-amber-100 text-amber-700' : 'bg-slate-100 text-slate-700'}`}>
                   {profile?.role === 'admin' ? 'Administrator' : 'Standard User'}
                 </span>
               </div>
             </div>
           </div>

           {profile?.role === 'admin' && (
             <div className="erp-card p-4 bg-amber-50 border-amber-200 flex gap-3 items-start">
                <ShieldAlert className="w-5 h-5 text-amber-600 shrink-0 mt-0.5" />
                <div>
                   <h4 className="text-sm font-semibold text-amber-900 mb-1">Elevated Privileges Active</h4>
                   <p className="text-xs text-amber-700/80 leading-relaxed">You hold administrative permissions. Be cautious when exercising system-wide modifications.</p>
                </div>
             </div>
           )}
        </div>
      </div>
    </SidebarLayout>
  );
}

import { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth.jsx';
import { getTripNotes, updateTripNotes } from '../lib/api.js';
import SidebarLayout from '../components/SidebarLayout.jsx';
import { useToast } from '../hooks/useToast.jsx';
import { Save, Loader2, FileText } from 'lucide-react';

export default function TripNotes() {
  const { id } = useParams();
  const { user } = useAuth();
  const { addToast } = useToast();

  const [notes, setNotes] = useState('');
  const [saving, setSaving] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    (async () => {
      try {
        const data = await getTripNotes(id);
        if (data) setNotes(data.notes || '');
      } catch (err) {
        addToast('Failed to load operational notes', 'error');
      } finally {
        setLoading(false);
      }
    })();
  }, [id, addToast]);

  const handleSave = async () => {
    setSaving(true);
    try {
      await updateTripNotes(id, notes);
      addToast('Document synchronized successfully', 'success');
    } catch (err) {
      addToast('Failed to synchronize document', 'error');
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <SidebarLayout title="Document Editor"><div className="p-6 text-sm text-slate-500">Loading document...</div></SidebarLayout>;

  return (
    <SidebarLayout title="Operational Notes" subtitle="Main text buffer for ad-hoc instructions, links, and operational details.">
      <div className="max-w-5xl mx-auto flex flex-col h-[calc(100vh-140px)]">

        <div className="erp-card flex flex-col h-full bg-white relative">
           <div className="px-5 py-3 border-b border-slate-200 bg-slate-50 flex items-center justify-between">
              <div className="flex items-center gap-2 text-slate-700 font-semibold text-sm">
                <FileText className="w-4 h-4 text-indigo-500" />
                Raw Text Document
              </div>
              <button 
                onClick={handleSave} 
                disabled={saving} 
                className="erp-button py-1.5 px-4 text-xs"
              >
                {saving ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Save className="w-3.5 h-3.5" />}
                {saving ? 'Syncing...' : 'Synchronize'}
              </button>
           </div>

           <div className="flex-1 p-0 relative">
             <textarea
               value={notes}
               onChange={(e) => setNotes(e.target.value)}
               placeholder="# Project Notes\n\n- Add flight confirmation numbers...\n- Important links..."
               className="w-full h-full resize-none p-6 text-sm placeholder:text-slate-300 font-mono text-slate-800 leading-relaxed focus:outline-none focus:ring-inset focus:ring-2 focus:ring-indigo-500/20"
             />
           </div>

           <div className="px-5 py-2 border-t border-slate-200 bg-slate-50 flex justify-between text-xs text-slate-500 font-medium">
             <span>Buffer formatting: Markdown Supported</span>
             <span>Words: {notes.split(/\s+/).filter(w => w.length > 0).length}</span>
           </div>
        </div>
      </div>
    </SidebarLayout>
  );
}
